import React, { useState } from "react";
import { useCart } from "../../context/CartContext";

const CustomizePackPage = () => {
  const { addToCart } = useCart();

  const itemsList = [
    { id: 1, name: "Rice", price: 60 },
    { id: 2, name: "Dal", price: 120 },
    { id: 3, name: "Oil", price: 150 },
  ];

  const [selected, setSelected] = useState([]);

  const toggleItem = (item) => {
    setSelected((prev) => {
      const exists = prev.find((i) => i.id === item.id);
      if (exists) return prev.filter((i) => i.id !== item.id);
      return [...prev, { ...item, qty: 1 }];
    });
  };

  const total = selected.reduce((sum, i) => sum + i.price * i.qty, 0);

  const handleAdd = () => {
    addToCart({
      _id: Date.now(),
      productName: "Custom Pack",
      price: total,
      discountedPrice: total,
      images: ["https://via.placeholder.com/150"],
      qty: 1,
      type: "subscription",
    });
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Customize Pack</h2>

      {itemsList.map((item) => (
        <div key={item.id}>
          <input type="checkbox" onChange={() => toggleItem(item)} />
          {item.name} - ₹{item.price}
        </div>
      ))}

      <h3>Total: ₹{total}</h3>

      <button onClick={handleAdd}>Add Pack</button>
    </div>
  );
};

export default CustomizePackPage;
